define _cnt_rectrcob		smallint;
define _orden               smallint;
define _cnt3     			smallint;
define _cnt2				smallint;
define _cnt					smallint;
define _error_isam			integer;
define _error				integer;
define _fecha_no_server		date;
define _vigencia_inic		date;

set isolation to dirty read;

begin

foreach with hold
	select no_tranrec,
		   no_reclamo,
		   cod_tipotran,
		   monto
	  into _no_tranrec,
		   _no_reclamo,
		   _cod_tipotran,
		   _monto
	  from rectrmae
	 where no_tranrec in('1975682','1975683','1975684','1975685','1975702','1975703','1975714','1975715','1975726','1975727','1975734','1975735','1975740','1975741','1975750','1975751','1975756','1975757','1975778','1975779','1975808','1975809','1975814','1975815',
                     '1975822','1975823','1975828','1975829','1975832','1975833','1975180','1974884','1974885','1974886','1974887','1974902','1974903','1974904','1974905','1974920','1974921','1974924','1974925','1974926','1974927','1974940','1974941','1974942',
                     '1974943','1974958','1974959','1974978','1974979','1974980','1974981','1974986','1974987','1974988','1974989','1974994','1974995','1975010','1975011','1975018','1975019','1975026','1975027','1975042','1975043','1975058','1975059','1975072',
