                     '1979610','1979611','1979620','1979621')

	
	select count(*)
	  into _cnt_rectrcob
	  from rectrcob
	 where no_tranrec = _no_tranrec;

	let _variacion = _monto;

	if _cod_tipotran = '003' then
		let _variacion = _monto * -1;
	end if

	if _cnt_rectrcob is null then
		let _cnt_rectrcob = 0;
	end if

	if _cnt_rectrcob > 1 then
		let _reserva2 = 0.00;
		foreach
			select sum(r.monto),
				   r.cod_cobertura
			  into _reserva_cob,
				   _cod_cobertura		  
			  from rectrcob r, rectrmae t
			 where r.no_tranrec = t.no_tranrec
			   and t.no_reclamo = _no_reclamo
			   and t.actualizado = 1
			   and t.periodo <= '2018-03'
			   and t.no_tranrec not in ('1975682','1975683','1975684','1975685','1975702','1975703','1975714','1975715','1975726','1975727','1975734','1975735','1975740','1975741','1975750','1975751','1975756','1975757','1975778','1975779','1975808','1975809','1975814','1975815',
