                     '1975374','1975375','1975402','1975403','1975414','1975415','1975416','1975417','1975420','1975421','1975434','1975435','1975438','1975439','1975450','1975451','1975478','1975479','1975498','1975499','1975500','1975501','1975514','1975515',
                     '1975546','1975547','1975548','1975549','1975566','1975567','1975582','1975583','1975648','1975649','1975650','1975651','1975670','1975671','1976692','1976693','1976694','1976695','1976696','1976697','1976718','1976719','1976724','1976725',
                     '1976726','1976727','1976740','1976741','1976768','1976769','1976788','1976789','1976828','1976829','1976844','1976845','1976900','1976901','1976920','1976921','1976946','1976947','1976966','1976967','1976974','1976975','1976982','1976983',
                     '1976986','1976987','1977012','1977013','1977024','1977025','1977046','1977047','1977048','1977049','1977050','1977051','1977062','1977063','1977078','1977079','1977094','1977095','1977124','1977125','1977142','1977143','1977146','1977147',
                     '1977154','1977155','1977156','1977157','1977164','1977165','1977166','1977167','1977178','1977179','1977186','1977187','1977214','1977215','1977228','1977229','1977232','1977233','1977234','1977235','1977236','1977237','1977248','1977249',
                     '1977250','1977251','1977256','1977257','1977272','1977273','1977302','1977303','1977306','1977307','1977324','1977325','1977336','1977337','1977362','1977363','1977366','1977367','1977374','1977375','1977388','1977389','1977418','1977419',
                     '1977454','1977455','1977462','1977463','1977470','1977471','1977482','1977483','1977506','1977507','1977516','1977517','1977532','1977533','1977572','1977573','1977574','1977575','1977578','1977579','1977580','1977581','1977582','1977583',
                     '1977584','1977585','1977592','1977593','1977604','1977605','1977606','1977607','1977610','1977611','1977612','1977613','1977616','1977617','1977652','1977653','1977656','1977657','1977670','1977671','1977676','1977677','1977686','1977687',
                     '1977688','1977689','1977730','1977731','1977736','1977737','1977748','1977749','1977754','1977755','1977762','1977763','1977766','1977767','1977772','1977773','1977774','1977775','1977776','1977777','1977782','1977783','1977824','1977825',
                     '1977828','1977829','1977848','1977849','1977850','1977851','1977862','1977863','1977868','1977869','1978170','1978171','1978178','1978179','1978186','1978187','1978188','1978189','1978192','1978193','1978230','1978231','1978246','1978247',
                     '1978248','1978249','1978268','1978269','1978274','1978275','1978286','1978287','1978308','1978309','1978312','1978313','1978314','1978315','1978316','1978317','1978324','1978325','1978326','1978327','1978334','1978335','1978336','1978337',
                     '1978346','1978347','1978348','1978349','1978362','1978363','1978374','1978375','1978378','1978379','1978384','1978385','1978390','1978391','1978396','1978397','1978432','1978433','1977628','1977629','1978472','1978473','1978474','1978475',
                     '1978508','1978509','1978516','1978517','1978526','1978527','1978556','1978557','1978580','1978581','1978596','1978597','1978600','1978601','1978602','1978603','1978612','1978613','1978652','1978653','1978698','1978699','1978710','1978711',
                     '1978748','1978749','1978754','1978755','1978766','1978767','1978770','1978771','1978786','1978787','1978788','1978789','1978794','1978795','1978798','1978799','1978824','1978825','1978846','1978847','1978852','1978853','1978858','1978859',
                     '1979190','1979191','1979194','1979195','1979246','1979247','1979274','1979275','1979276','1979277','1979332','1979333','1979336','1979337','1979348','1979349','1979490','1979491','1979518','1979519','1979566','1979567','1979596','1979597',
                     '1979610','1979611','1979620','1979621')
			 group by r.cod_cobertura
			having sum(r.variacion) <> 0

			let _reserva_cob = _reserva_cob - _reserva2;

			if _monto < _reserva_cob then
				let _reserva_cob = _monto;
			end if

			if _cod_tipotran = '003' then
				let _variacion = _reserva_cob * -1;
			end if

			if _reserva_cob <= 0.00 then
				let _reserva_cob = 0.00;
				let _variacion = 0.00;
			end if

			update rectrcob
			   set monto = _reserva_cob,
				   variacion = _variacion
			 where no_tranrec = _no_tranrec
			   and cod_cobertura = _cod_cobertura;

			let _reserva2 = _reserva2 + _reserva_cob;
		end foreach
	else
		update rectrcob
		   set monto = _monto,
			   variacion = _variacion
		 where no_tranrec = _no_tranrec;
	end if
